import React from "react";
import { getImage } from "../../utils/getImage";
import LazyImage from "../../components/LazyImage";

export default function GridItem({ item, selected, onClick }) {
  return (
    <button
      type="button"
      onClick={onClick}
      style={{
        all: "unset",
        display: "block",
        cursor: "pointer",
        width: "100%",
        borderRadius: "12px",
        overflow: "hidden",
        background: "#fff",
        border: selected ? "2px solid #666" : "1px solid #e5e5e5",
      }}
    >
      <div style={{ height: "200px", position: "relative" }}>
        <LazyImage
          src={getImage(item, "thumb")}
          alt={item.titulo}
          style={{
            width: "100%",
            height: "100%",
            objectFit: "contain",
            position: "absolute",
          }}
        />
      </div>

      <div style={{ padding: "10px" }}>
        <div style={{ fontWeight: "bold" }}>{item.titulo}</div>
        <div style={{ fontSize: "12px", color: "#666" }}>
          {item.descripcion}
        </div>
      </div>
    </button>
  );
}
